SELECT count(*) FROM movie_keyword, keyword, title, cast_info, role_type, movie_companies, char_name WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_companies.movie_id = title.id AND cast_info.person_role_id = char_name.id;